109	uint8_t ll_adv_aux_ad_data_set(uint8_t handle, uint8_t op, uint8_t frag_pref,
110				       uint8_t len, uint8_t const *const data)
111	{
112		uint8_t hdr_data[ULL_ADV_HDR_DATA_LEN_SIZE +
113				 ULL_ADV_HDR_DATA_DATA_PTR_SIZE +
114				 ULL_ADV_HDR_DATA_LEN_SIZE +
115				 ULL_ADV_HDR_DATA_AUX_PTR_PTR_SIZE +
116				 ULL_ADV_HDR_DATA_LEN_SIZE];
117		uint8_t pri_idx, sec_idx;
118		struct ll_adv_set *adv;
119		uint8_t *val_ptr;
120		uint8_t err;
121	
122	#if defined(CONFIG_BT_CTLR_ADV_AUX_PDU_LINK)
123		struct pdu_adv *pdu_prev;
124		uint8_t ad_len_overflow;
125		uint8_t ad_len_chain;
126		struct pdu_adv *pdu;
127		uint8_t ad_len = 0U;
128	#endif /* CONFIG_BT_CTLR_ADV_AUX_PDU_LINK */
129	
130		/* Get the advertising set instance */
131		adv = ull_adv_is_created_get(handle);
132		if (!adv) {
133			return BT_HCI_ERR_UNKNOWN_ADV_IDENTIFIER;
134		}
135	
136		/* Reject setting fragment when Extended Advertising is enabled */
137		if (adv->is_enabled && (op <= BT_HCI_LE_EXT_ADV_OP_LAST_FRAG)) {
138			return BT_HCI_ERR_CMD_DISALLOWED;
139		}
140	
141		/* Reject intermediate op before first op */
142		if (adv->is_ad_data_cmplt &&
143		    ((op == BT_HCI_LE_EXT_ADV_OP_INTERM_FRAG) ||
144		     (op == BT_HCI_LE_EXT_ADV_OP_LAST_FRAG))) {
145			return BT_HCI_ERR_CMD_DISALLOWED;
146		}
147	
148		/* Reject unchanged op before complete status */
149		if (!adv->is_ad_data_cmplt &&
150		    (op == BT_HCI_LE_EXT_ADV_OP_UNCHANGED_DATA)) {
151			return BT_HCI_ERR_CMD_DISALLOWED;
152		}
153	
154		/* Reject len > 191 bytes if chain PDUs unsupported */
155		if (!IS_ENABLED(CONFIG_BT_CTLR_ADV_AUX_PDU_LINK) &&
156		    (len > PDU_AC_EXT_AD_DATA_LEN_MAX)) {
157			return BT_HCI_ERR_CMD_DISALLOWED;
158		}
159	
160		/* Prepare the AD data as parameter to update in PDU */
161		/* Use length = 0 and NULL pointer to retain old data in the PDU.
162		 * Use length = 0 and valid pointer of `data` (auto/local variable) to
163		 * remove old data.
164		 * User length > 0 and valid pointer of `data` (auto/local variable) to
165		 * set new data.
166		 */
167		val_ptr = hdr_data;
168		if ((IS_ENABLED(CONFIG_BT_CTLR_ADV_AUX_PDU_LINK) && (
169		     op == BT_HCI_LE_EXT_ADV_OP_INTERM_FRAG ||
170		     op == BT_HCI_LE_EXT_ADV_OP_LAST_FRAG)) ||
171		    op == BT_HCI_LE_EXT_ADV_OP_UNCHANGED_DATA) {
172			*val_ptr++ = 0U;
173			(void)memset((void *)val_ptr, 0U,
174				     ULL_ADV_HDR_DATA_DATA_PTR_SIZE);
175		} else {
176			*val_ptr++ = len;
177			(void)memcpy(val_ptr, &data, sizeof(data));
178		}
179	
180		if ((!IS_ENABLED(CONFIG_BT_CTLR_ADV_AUX_PDU_LINK) &&
181		     (op == BT_HCI_LE_EXT_ADV_OP_COMPLETE_DATA ||
182		      op == BT_HCI_LE_EXT_ADV_OP_FIRST_FRAG)) ||
183		    (op == BT_HCI_LE_EXT_ADV_OP_UNCHANGED_DATA)) {
184			err = ull_adv_aux_hdr_set_clear(adv,
185							ULL_ADV_PDU_HDR_FIELD_AD_DATA,
186							0U, hdr_data, &pri_idx,
187							&sec_idx);
188	#if defined(CONFIG_BT_CTLR_ADV_AUX_PDU_LINK)
189			/* No AD data overflow */
190			ad_len_overflow = 0U;
191	
192			/* No AD data in chain PDU */
193			ad_len_chain = 0U;
194	
195			/* local variables not used due to overflow being 0 */
196			pdu_prev = NULL;
197			pdu = NULL;
198		} else if (op == BT_HCI_LE_EXT_ADV_OP_FIRST_FRAG ||
199			    op == BT_HCI_LE_EXT_ADV_OP_COMPLETE_DATA) {
200			/* Add AD Data and remove any prior presence of Aux Ptr */

			     const struct pdu_adv *pdu,
			     uint8_t pdu_len, uint8_t pdu_scan_len)
{
	const struct lll_adv_aux *lll_aux;
	const struct lll_adv *lll;
	uint32_t time_us;

	lll_aux = &aux->lll;
	lll = lll_aux->adv;

	if (IS_ENABLED(CONFIG_BT_CTLR_ADV_RESERVE_MAX) &&
	    (lll->phy_s == PHY_CODED)) {
		pdu_len = PDU_AC_EXT_PAYLOAD_OVERHEAD;
		pdu_scan_len = PDU_AC_EXT_PAYLOAD_OVERHEAD;
	}

	/* NOTE: 16-bit values are sufficient for minimum radio event time
	 *       reservation, 32-bit are used here so that reservations for
	 *       whole back-to-back chaining of PDUs can be accommodated where
	 *       the required microseconds could overflow 16-bits, example,
	 *       back-to-back chained Coded PHY PDUs.
	 */
	time_us = PDU_AC_US(pdu_len, lll->phy_s, lll->phy_flags) +
		  EVENT_OVERHEAD_START_US + EVENT_OVERHEAD_END_US;

	if ((pdu->adv_ext_ind.adv_mode & BT_HCI_LE_ADV_PROP_CONN) ==
	    BT_HCI_LE_ADV_PROP_CONN) {
		const uint16_t conn_req_us =
			PDU_AC_MAX_US((INITA_SIZE + ADVA_SIZE + LLDATA_SIZE),
				      lll->phy_s);
		const uint16_t conn_rsp_us =
			PDU_AC_US((PDU_AC_EXT_HEADER_SIZE_MIN + ADVA_SIZE +
				   TARGETA_SIZE), lll->phy_s, lll->phy_flags);

		time_us += EVENT_IFS_MAX_US * 2 + conn_req_us + conn_rsp_us;
	} else if ((pdu->adv_ext_ind.adv_mode & BT_HCI_LE_ADV_PROP_SCAN) ==
		   BT_HCI_LE_ADV_PROP_SCAN) {
		const uint16_t scan_req_us  =
			PDU_AC_MAX_US((SCANA_SIZE + ADVA_SIZE), lll->phy_s);
		const uint16_t scan_rsp_us =
			PDU_AC_US(pdu_scan_len, lll->phy_s, lll->phy_flags);

		time_us += EVENT_IFS_MAX_US * 2 + scan_req_us + scan_rsp_us;

		/* FIXME: Calculate additional time reservations for scan
		 *        response chain PDUs, if any.
		 */
	} else {
		/* Non-connectable Non-Scannable */

#if defined(CONFIG_BT_CTLR_ADV_AUX_PDU_LINK)
		const struct pdu_adv *pdu_chain;

		/* Calculate additional time reservations for chain PDUs, if any. */
		pdu_chain = lll_adv_pdu_linked_next_get(pdu);
		while (pdu_chain != NULL) {
			time_us += EVENT_B2B_MAFS_US;
			time_us += PDU_AC_US(pdu_chain->len, lll->phy_s, lll->phy_flags);
			pdu_chain = lll_adv_pdu_linked_next_get(pdu_chain);
		}
#endif /* CONFIG_BT_CTLR_ADV_AUX_PDU_LINK */
	}

	return time_us;
}

static uint32_t aux_time_min_get(const struct ll_adv_aux_set *aux)
{
	const struct lll_adv_aux *lll_aux;
	const struct pdu_adv *pdu_scan;
	const struct lll_adv *lll;
	const struct pdu_adv *pdu;
	uint8_t pdu_scan_len;
	uint8_t pdu_len;

	lll_aux = &aux->lll;
	lll = lll_aux->adv;
	pdu = lll_adv_aux_data_peek(lll_aux);
	pdu_scan = lll_adv_scan_rsp_peek(lll);

	/* Calculate the PDU Tx Time and hence the radio event length,
	 * Always use maximum length for common extended header format so that
	 * ACAD could be update when periodic advertising is active and the
	 * time reservation need not be updated every time avoiding overlapping
	 * with other active states/roles.
	 */
	pdu_len = pdu->len - pdu->adv_ext_ind.ext_hdr_len -
		  PDU_AC_EXT_HEADER_SIZE_MIN + PDU_AC_EXT_HEADER_SIZE_MAX;
	pdu_scan_len = pdu_scan->len - pdu_scan->adv_ext_ind.ext_hdr_len -
		       PDU_AC_EXT_HEADER_SIZE_MIN + PDU_AC_EXT_HEADER_SIZE_MAX;

	return aux_time_get(aux, pdu, pdu_len, pdu_scan_len);
}

static uint8_t aux_time_update(struct ll_adv_aux_set *aux, struct pdu_adv *pdu,
			       struct pdu_adv *pdu_scan)
{
	uint32_t time_ticks;
	uint32_t time_us;

	time_us = aux_time_min_get(aux);

	return 0;
}

